const result = {
  data: {}
};

$input.all().forEach((item) => {
    const categories = item.json.category;
    const sums = item.json.sum;

    categories.forEach((category, index) => {
    const normalizedCategory = category.toLowerCase();
    const value = sums[index];

    if (result.data[normalizedCategory]) {
        result.data[normalizedCategory] += value;
      } else {
        result.data[normalizedCategory] = value;
      }
    });
  }
)

const outputArray = Object.entries(result).map(([category, sum]) => ({
  [category]: sum
}));

return outputArray;

const tempData = {};

$input.all().forEach((item) => {
    const categories = item.json.category;
    const sums = item.json.sum;
    const userIds = item.json.user_id;

    categories.forEach((category, index) => {
        const normalizedCategory = category.toLowerCase();
        const value = sums[index];
        const userId = userIds[index];

        if (!tempData[userId]) {
            tempData[userId] = {
                user_id: userId,
                categories: {},
                total: 0
            };
        }

        if (tempData[userId].categories[normalizedCategory]) {
            tempData[userId].categories[normalizedCategory] += value;
        } else {
            tempData[userId].categories[normalizedCategory] = value;
        }

        tempData[userId].total += value;
    });
});

const result = {
    data: Object.values(tempData).map(user => ({
        user_id: user.user_id,
        categories: user.categories,
        total: user.total
    }))
};

return result.data;
